import React, { useState, useRef } from 'react';
import { Package, DollarSign, Calendar, Image as ImageIcon, X, Upload } from 'lucide-react';

const FormularioOferta = ({ onSave, onCancel }) => {
  const fileInputRef = useRef(null);
  const [formData, setFormData] = useState({
    producto: '',
    precio: '',
    vencimiento: '',
    descripcion: '',
    imagen: null
  });
  const [preview, setPreview] = useState(null);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result);
        setFormData({ ...formData, imagen: reader.result });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (parseFloat(formData.precio) <= 0) {
      alert("Por favor, ingresa un precio válido.");
      return;
    }
    onSave(formData);
  };

  return (
    <div style={formCardStyle}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
        <h3 style={{ margin: 0 }}>Publicar Nueva Oferta</h3>
        <button onClick={onCancel} style={btnCerrar}><X size={20} /></button>
      </div>

      <form onSubmit={handleSubmit}>
        <div style={inputGroup}>
          <label style={labelStyle}><Package size={16} /> Producto</label>
          <input 
            style={inputStyle} 
            type="text" 
            placeholder="Ej: Leche Larga Vida 1L" 
            required
            value={formData.producto}
            onChange={(e) => setFormData({...formData, producto: e.target.value})}
          />
        </div>

        <div style={{ display: 'flex', gap: '20px' }}>
          <div style={{ ...inputGroup, flex: 1 }}>
            <label style={labelStyle}><DollarSign size={16} /> Precio</label>
            <input 
              style={inputStyle} 
              type="number" 
              placeholder="0.00" 
              required
              value={formData.precio}
              onChange={(e) => setFormData({...formData, precio: e.target.value})}
            />
          </div>
          <div style={{ ...inputGroup, flex: 1 }}>
            <label style={labelStyle}><Calendar size={16} /> Vencimiento</label>
            <input 
              style={inputStyle} 
              type="date" 
              required
              value={formData.vencimiento}
              onChange={(e) => setFormData({...formData, vencimiento: e.target.value})}
            />
          </div>
        </div>

        <div style={inputGroup}>
          <label style={labelStyle}><ImageIcon size={16} /> Foto del Producto</label>
          <div 
            style={dropzoneStyle} 
            onClick={() => fileInputRef.current.click()}
          >
            {preview ? (
              <img src={preview} alt="Vista previa" style={previewStyle} />
            ) : (
              <div style={placeholderStyle}>
                <Upload size={24} color="#94a3b8" />
                <p style={{ margin: '5px 0 0', fontSize: '0.85rem' }}>Click para subir imagen</p>
              </div>
            )}
            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleImageChange} 
              accept="image/*" 
              style={{ display: 'none' }} 
            />
          </div>
        </div>

        <div style={inputGroup}>
          <label style={labelStyle}>Descripción / Nota</label>
          <textarea 
            style={{ ...inputStyle, height: '80px', resize: 'none' }} 
            placeholder="Ej: Máximo 3 unidades por persona"
            value={formData.descripcion}
            onChange={(e) => setFormData({...formData, descripcion: e.target.value})}
          />
        </div>

        <button type="submit" style={btnPublicar}>Publicar Ahora</button>
      </form>
    </div>
  );
};

/* --- ESTILOS --- */
const formCardStyle = { background: 'white', padding: '30px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.05)', border: '1px solid #e2e8f0' };
const inputGroup = { marginBottom: '15px' };
const labelStyle = { display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px', fontWeight: '600', color: '#1e293b' };
const inputStyle = { width: '100%', padding: '12px', borderRadius: '10px', border: '1px solid #cbd5e1', boxSizing: 'border-box', fontSize: '1rem' };
const dropzoneStyle = { border: '2px dashed #cbd5e1', borderRadius: '12px', height: '120px', display: 'flex', justifyContent: 'center', alignItems: 'center', cursor: 'pointer', overflow: 'hidden', background: '#f8fafc', transition: 'all 0.3s' };
const previewStyle = { width: '100%', height: '100%', objectFit: 'cover' };
const placeholderStyle = { textAlign: 'center', color: '#94a3b8' };
const btnPublicar = { width: '100%', padding: '14px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer', marginTop: '10px', fontSize: '1rem' };
const btnCerrar = { background: 'none', border: 'none', cursor: 'pointer', color: '#64748b' };

export default FormularioOferta;
